11	/** @file   nerfloader.cu
12	 *  @author Alex Evans & Thomas Müller, NVIDIA
13	 *  @brief  Loads a NeRF data set from NeRF's original format
14	 */
15	
16	#include <neural-graphics-primitives/common_device.cuh>
17	#include <neural-graphics-primitives/common.h>
18	#include <neural-graphics-primitives/nerf_loader.h>
19	#include <neural-graphics-primitives/thread_pool.h>
20	#include <neural-graphics-primitives/tinyexr_wrapper.h>
21	
22	#include <filesystem/path.h>
23	
24	#include <json/json.hpp>
25	
26	#include <natural_sort.hpp>
27	
28	#include <stb_image/stb_image.h>
29	
30	#define _USE_MATH_DEFINES
31	#include <cmath>
32	#include <cstdlib>
33	#include <fstream>
34	#include <string>
35	#include <vector>
36	
37	using namespace std::literals;
38	
39	namespace ngp {
40	
41	__global__ void convert_rgba32(const uint64_t num_pixels, const uint8_t* __restrict__ pixels, uint8_t* __restrict__ out, bool white_2_transparent = false, bool black_2_transparent = false, uint32_t mask_color = 0) {
42		const uint64_t i = threadIdx.x + blockIdx.x * blockDim.x;
43		if (i >= num_pixels) return;
44	
45		uint8_t rgba[4];
46		*((uint32_t*)&rgba[0]) = *((uint32_t*)&pixels[i*4]);
47	
48		// NSVF dataset has 'white = transparent' madness
49		if (white_2_transparent && rgba[0] == 255 && rgba[1] == 255 && rgba[2] == 255) {
50			rgba[3] = 0;
51		}
52	
53		if (black_2_transparent && rgba[0] == 0 && rgba[1] == 0 && rgba[2] == 0) {
54			rgba[3] = 0;
55		}
56	
57		if (mask_color != 0 && mask_color == *((uint32_t*)&rgba[0])) {
58			// turn the mask into hot pink
59			rgba[0] = 0xFF; rgba[1] = 0x00; rgba[2] = 0xFF; rgba[3] = 0x00;
60		}
61	
62		*((uint32_t*)&out[i*4]) = *((uint32_t*)&rgba[0]);
63	}
64	
65	__global__ void from_fullp(const uint64_t num_elements, const float* __restrict__ pixels, __half* __restrict__ out) {
66		const uint64_t i = threadIdx.x + blockIdx.x * blockDim.x;
67		if (i >= num_elements) return;
68	
69		out[i] = (__half)pixels[i];
70	}
71	
72	template <typename T>
73	__global__ void copy_depth(const uint64_t num_elements, float* __restrict__ depth_dst, const T* __restrict__ depth_pixels, float depth_scale) {
74		const uint64_t i = threadIdx.x + blockIdx.x * blockDim.x;
75		if (i >= num_elements) return;
76	
77		if (depth_pixels == nullptr || depth_scale <= 0.f) {
78			depth_dst[i] = 0.f; // no depth data for this entire image. zero it out
79		} else {
80			depth_dst[i] = depth_pixels[i] * depth_scale;
81		}
82	}
83	
84	template <typename T>
85	__global__ void sharpen(const uint64_t num_pixels, const uint32_t w, const T* __restrict__ pix, T* __restrict__ destpix, float center_w, float inv_totalw) {
86		const uint64_t i = threadIdx.x + blockIdx.x * blockDim.x;
87		if (i >= num_pixels) return;
88	
89		float rgba[4] = {
90			(float)pix[i*4+0]*center_w,
91			(float)pix[i*4+1]*center_w,
92			(float)pix[i*4+2]*center_w,
93			(float)pix[i*4+3]*center_w
94		};
95	
96		int64_t i2=i-1; if (i2<0) i2=0; i2*=4;
97		for (int j=0;j<4;++j) rgba[j]-=(float)pix[i2++];
98		i2=i-w; if (i2<0) i2=0; i2*=4;
99		for (int j=0;j<4;++j) rgba[j]-=(float)pix[i2++];
100		i2=i+1; if (i2>=num_pixels) i2-=num_pixels; i2*=4;
101		for (int j=0;j<4;++j) rgba[j]-=(float)pix[i2++];
102		i2=i+w; if (i2>=num_pixels) i2-=num_pixels; i2*=4;
103		for (int j=0;j<4;++j) rgba[j]-=(float)pix[i2++];
104		for (int j=0;j<4;++j) destpix[i*4+j]=(T)max(0.f, rgba[j] * inv_totalw);
105	}
106	
107	__device__ inline float luma(const vec4& c) {
108		return c[0] * 0.2126f + c[1] * 0.7152f + c[2] * 0.0722f;
109	}
110	
111	__global__ void compute_sharpness(ivec2 sharpness_resolution, ivec2 image_resolution, uint32_t n_images, const void* __restrict__ images_data, EImageDataType image_data_type, float* __restrict__ sharpness_data) {
112		const uint32_t x = threadIdx.x + blockIdx.x * blockDim.x;
113		const uint32_t y = threadIdx.y + blockIdx.y * blockDim.y;
114		const uint32_t i = threadIdx.z + blockIdx.z * blockDim.z;
115		if (x >= sharpness_resolution.x || y >= sharpness_resolution.y || i>=n_images) return;
116		const size_t sharp_size = sharpness_resolution.x * sharpness_resolution.y;
117		sharpness_data += sharp_size * i + x + y * sharpness_resolution.x;
118	
119		// overlap patches a bit
120		int x_border = 0; // (image_resolution.x/sharpness_resolution.x)/4;
121		int y_border = 0; // (image_resolution.y/sharpness_resolution.y)/4;
122	
123		int x1 = (x*image_resolution.x)/sharpness_resolution.x-x_border, x2 = ((x+1)*image_resolution.x)/sharpness_resolution.x+x_border;
124		int y1 = (y*image_resolution.y)/sharpness_resolution.y-y_border, y2 = ((y+1)*image_resolution.y)/sharpness_resolution.y+y_border;
125		// clamp to 1 pixel in from edge
126		x1=max(x1,1); y1=max(y1,1);
127		x2=min(x2,image_resolution.x-2); y2=min(y2,image_resolution.y-2);
128		// yes, yes I know I should do a parallel reduction and shared memory and stuff. but we have so many tiles in flight, and this is load-time, meh.
129		float tot_lap=0.f,tot_lap2=0.f,tot_lum=0.f;
130		float scal=1.f/((x2-x1)*(y2-y1));
131		for (int yy=y1;yy<y2;++yy) {
132			for (int xx=x1; xx<x2; ++xx) {
133				vec4 n, e, s, w, c;
134				c = read_rgba(ivec2{xx, yy}, image_resolution, images_data, image_data_type, i);
135				n = read_rgba(ivec2{xx, yy-1}, image_resolution, images_data, image_data_type, i);
136				w = read_rgba(ivec2{xx-1, yy}, image_resolution, images_data, image_data_type, i);
137				s = read_rgba(ivec2{xx, yy+1}, image_resolution, images_data, image_data_type, i);
138				e = read_rgba(ivec2{xx+1, yy}, image_resolution, images_data, image_data_type, i);
139				float lum = luma(c);
140				float lap = lum * 4.f - luma(n) - luma(e) - luma(s) - luma(w);
141				tot_lap += lap;
142				tot_lap2 += lap*lap;
143				tot_lum += lum;
144			}
145		}
146		tot_lap*=scal;
147		tot_lap2*=scal;
148		tot_lum*=scal;
149		float variance_of_laplacian = tot_lap2 - tot_lap * tot_lap;
150		*sharpness_data = (variance_of_laplacian) ; // / max(0.00001f,tot_lum*tot_lum); // var / (tot+0.001f);
151	}
152	
153	NerfDataset create_empty_nerf_dataset(size_t n_images, int aabb_scale, bool is_hdr) {
154		NerfDataset result{};
155		result.n_images = n_images;
156		result.sharpness_resolution = { 128, 72 };
157		result.sharpness_data.enlarge( result.sharpness_resolution.x * result.sharpness_resolution.y *  result.n_images );
158		result.xforms.resize(n_images);
159		result.metadata.resize(n_images);
160		result.pixelmemory.resize(n_images);
161		result.depthmemory.resize(n_images);
162		result.raymemory.resize(n_images);
163		result.scale = NERF_SCALE;
164		result.offset = {0.5f, 0.5f, 0.5f};
165		result.aabb_scale = aabb_scale;
166		result.is_hdr = is_hdr;
167		result.paths = std::vector<std::string>(n_images, "");
168		for (size_t i = 0; i < n_images; ++i) {
169			result.xforms[i].start = mat4x3::identity();
170			result.xforms[i].end = mat4x3::identity();
171		}
172		return result;
173	}
174	
175	void read_lens(const nlohmann::json& json, Lens& lens, vec2& principal_point, vec4& rolling_shutter) {
176		ELensMode mode = ELensMode::Perspective;
177	
178		ELensMode opencv_mode = json.value("is_fisheye", false) ? ELensMode::OpenCVFisheye : ELensMode::OpenCV;
179		auto read_opencv_parameter = [&](const std::string& name, size_t idx) {
180			if (json.contains(name)) {
181				lens.params[idx] = json[name];
182				if (lens.params[idx] != 0.f) {
183					mode = opencv_mode;
184				}
185			}
186		};
187	
188		read_opencv_parameter("k1", 0);
189		read_opencv_parameter("k2", 1);
190		read_opencv_parameter("k3", 2);
191		read_opencv_parameter("k4", 3);
192	
193		read_opencv_parameter("p1", 2);
194		read_opencv_parameter("p2", 3);
195	
196		if (json.contains("cx")) {
197			principal_point.x = (float)json["cx"] / (float)json["w"];
198		}
199	
200		if (json.contains("cy")) {
201			principal_point.y = (float)json["cy"] / (float)json["h"];
202		}
203	
204		if (json.contains("rolling_shutter")) {
205			// The rolling shutter is a float4 of [A,B,C,D] where the time
206			// for each pixel is t= A + B * u + C * v + D * motionblur_time,
207			// where u and v are the pixel coordinates within (0-1).
208			// The resulting t is used to interpolate between the start
209			// and end transforms for each training xform.
210			float motionblur_amount = 0.f;
211			if (json["rolling_shutter"].size() >= 4) {
212				motionblur_amount = float(json["rolling_shutter"][3]);
213			}
214	
215			rolling_shutter = {float(json["rolling_shutter"][0]), float(json["rolling_shutter"][1]), float(json["rolling_shutter"][2]), motionblur_amount};
216		}
217	
218		if (json.contains("ftheta_p0")) {
219			lens.params[0] = json["ftheta_p0"];
220			lens.params[1] = json["ftheta_p1"];
221			lens.params[2] = json["ftheta_p2"];
222			lens.params[3] = json["ftheta_p3"];
223			lens.params[4] = json["ftheta_p4"];
224			lens.params[5] = json["w"];
225			lens.params[6] = json["h"];
226			mode = ELensMode::FTheta;
227		}
228	
229		if (json.contains("latlong")) {
230			mode = ELensMode::LatLong;
231		} else if (json.contains("equirectangular")) {
232			mode = ELensMode::Equirectangular;
233		} else if (json.contains("orthographic")) {
234			mode = ELensMode::Orthographic;
235		}
236	
237		// If there was an outer distortion mode, don't override it with nothing.
238		if (mode != ELensMode::Perspective) {
239			lens.mode = mode;
240		}
241	}
