243	bool read_focal_length(const nlohmann::json &json, vec2 &focal_length, const ivec2 &res) {
244		auto read_focal_length = [&](int resolution, const std::string& axis) {
245			if (json.contains(axis + "_fov")) {
246				return fov_to_focal_length(resolution, (float)json[axis + "_fov"]);
247			} else if (json.contains("fl_"s + axis)) {
248				return (float)json["fl_"s + axis];
249			} else if (json.contains("camera_angle_"s + axis)) {
250				return fov_to_focal_length(resolution, (float)json["camera_angle_"s + axis] * 180 / PI());
251			} else {
252				return 0.0f;
253			}
254		};
255	
256		// x_fov is in degrees, camera_angle_x in radians. Yes, it's silly.
257		float x_fl = read_focal_length(res.x, "x");
258		float y_fl = read_focal_length(res.y, "y");
259	
260		if (x_fl != 0) {
261			focal_length = vec2(x_fl);
262			if (y_fl != 0) {
263				focal_length.y = y_fl;
264			}
265		} else if (y_fl != 0) {
266			focal_length = vec2(y_fl);
267		} else {
268			return false;
269		}
270		return true;
271	}
