273	NerfDataset load_nerf(const std::vector<fs::path>& jsonpaths, float sharpen_amount) {
274		if (jsonpaths.empty()) {
275			throw std::runtime_error{"Cannot load NeRF data from an empty set of paths."};
276		}
277	
278		tlog::info() << "Loading NeRF dataset from";
279	
280		NerfDataset result{};
281	
282		std::ifstream f{native_string(jsonpaths.front())};
283		nlohmann::json transforms = nlohmann::json::parse(f, nullptr, true, true);
284	
285		ThreadPool pool;
286	
287		struct LoadedImageInfo {
288			ivec2 res = ivec2(0);
289			bool image_data_on_gpu = false;
290			EImageDataType image_type = EImageDataType::None;
291			bool white_transparent = false;
292			bool black_transparent = false;
293			uint32_t mask_color = 0;
294			void *pixels = nullptr;
295			uint16_t *depth_pixels = nullptr;
296			Ray *rays = nullptr;
297			float depth_scale = -1.f;
298		};
299		std::vector<LoadedImageInfo> images;
300		LoadedImageInfo info = {};
301	
302		if (transforms["camera"].is_array()) {
303			throw std::runtime_error{"hdf5 is no longer supported. please use the hdf52nerf.py conversion script"};
304		}
305	
306		// nerf original format
307		std::vector<nlohmann::json> jsons;
308		std::transform(
309			jsonpaths.begin(), jsonpaths.end(),
310			std::back_inserter(jsons), [](const auto& path) {
311				return nlohmann::json::parse(std::ifstream{native_string(path)}, nullptr, true, true);
312			}
313		);
314	
315		std::vector<std::string> supported_image_formats = {
316			"png", "jpg", "jpeg", "bmp", "gif", "tga", "pic", "pnm", "psd", "exr",
317		};
318	
319		auto resolve_path = [&supported_image_formats](const fs::path& base_path, const fs::path& local_path) {
320			fs::path path = local_path.is_absolute() ? local_path : (base_path / local_path);
321			if (path.extension().empty() && !path.exists()) {
322				for (const auto& format : supported_image_formats) {
323					if (path.with_extension(format).exists()) {
324						return path.with_extension(format);
325					}
326				}
327			}
328	
329			return path;
330		};
331	
332		result.n_images = 0;
333		for (size_t i = 0; i < jsons.size(); ++i) {
334			auto& json = jsons[i];
335			fs::path base_path = jsonpaths[i].parent_path();
336	
337	
338			if (!json.contains("frames") || !json["frames"].is_array()) {
339				tlog::warning() << "  " << jsonpaths[i] << " does not contain any frames. Skipping.";
340				continue;
341			}
342			tlog::info() << "  " << jsonpaths[i];
343			auto& frames = json["frames"];
344	
345			float sharpness_discard_threshold = json.value("sharpness_discard_threshold", 0.0f); // Keep all by default
346	
347			std::sort(frames.begin(), frames.end(), [](const auto& frame1, const auto& frame2) {
348				return SI::natural::compare<std::string>(frame1["file_path"], frame2["file_path"]);
349			});
350	
351			for (auto&& frame : frames) {
352				// Compatibility with Windows paths on Linux. (Breaks linux filenames with "\\" in them, which is acceptable for us.)
353				frame["file_path"] = replace_all(frame["file_path"], "\\", "/");
354				if (frame.contains("depth_path")) {
355					frame["depth_path"] = replace_all(frame["depth_path"], "\\", "/");
356				}
357			}
358	
359			if (json.contains("n_frames")) {
360				size_t cull_idx = std::min(frames.size(), (size_t)json["n_frames"]);
361				frames.get_ptr<nlohmann::json::array_t*>()->resize(cull_idx);
362			}
363	
364			if (frames[0].contains("sharpness")) {
365				auto frames_copy = frames;
366				frames.clear();
367	
368				// Kill blurrier frames than their neighbors
369				const int neighborhood_size = 3;
370				for (int i = 0; i < (int)frames_copy.size(); ++i) {
371					float mean_sharpness = 0.0f;
372					int mean_start = std::max(0, i-neighborhood_size);
373					int mean_end = std::min(i + neighborhood_size, (int)frames_copy.size() - 1);
374					for (int j = mean_start; j < mean_end; ++j) {
375						mean_sharpness += float(frames_copy[j].value("sharpness", 1.0));
376					}
377	
378					mean_sharpness /= (mean_end - mean_start);
379	
380					if (resolve_path(base_path, frames_copy[i]["file_path"]).exists() && frames_copy[i].value("sharpness", 1.0) > sharpness_discard_threshold * mean_sharpness) {
381						frames.emplace_back(frames_copy[i]);
382					} else {
383						// tlog::info() << "discarding frame " << frames_copy[i]["file_path"];
384						// fs::remove(resolve_path(base_path, frames_copy[i]["file_path"]));
385					}
386				}
387			}
388	
389			for (size_t i = 0; i < frames.size(); ++i) {
390				result.paths.emplace_back(frames[i]["file_path"]);
391			}
392	
393			result.n_images += frames.size();
394		}
395	
396		images.resize(result.n_images);
397		result.xforms.resize(result.n_images);
398		result.metadata.resize(result.n_images);
399		result.pixelmemory.resize(result.n_images);
400		result.depthmemory.resize(result.n_images);
401		result.raymemory.resize(result.n_images);
402	
403		result.scale = NERF_SCALE;
404		result.offset = {0.5f, 0.5f, 0.5f};
405	
406		std::vector<std::future<void>> futures;
407	
408		size_t image_idx = 0;
409	
410		if (result.n_images == 0) {
411			throw std::invalid_argument{"No training images were found for NeRF training!"};
412		}
413	
414		auto progress = tlog::progress(result.n_images);
415	
416		result.from_mitsuba = false;
417		bool fix_premult = false;
418		bool enable_ray_loading = true;
419		bool enable_depth_loading = true;
420		std::atomic<int> n_loaded{0};
421		BoundingBox cam_aabb;
422		for (size_t i = 0; i < jsons.size(); ++i) {
423			auto& json = jsons[i];
424	
425			fs::path base_path = jsonpaths[i].parent_path();
426			std::string jp = jsonpaths[i].str();
427			auto lastdot = jp.find_last_of('.'); if (lastdot==std::string::npos) lastdot = jp.length();
428			auto lastunderscore = jp.find_last_of('_'); if (lastunderscore == std::string::npos) lastunderscore=lastdot; else lastunderscore++;
429			std::string part_after_underscore(jp.begin()+lastunderscore,jp.begin()+lastdot);
430	
431			if (json.contains("enable_ray_loading")) {
432				enable_ray_loading = bool(json["enable_ray_loading"]);
433				tlog::info() << "enable_ray_loading=" << enable_ray_loading;
434			}
435			if (json.contains("enable_depth_loading")) {
436				enable_depth_loading = bool(json["enable_depth_loading"]);
437				tlog::info() << "enable_depth_loading is " << enable_depth_loading;
438			}
439	
440			if (json.contains("normal_mts_args")) {
441				result.from_mitsuba = true;
442			}
443	
444			if (json.contains("from_mitsuba")) {
445				result.from_mitsuba = bool(json["from_mitsuba"]);
446			}
447	
448			if (json.contains("fix_premult")) {
449				fix_premult = (bool)json["fix_premult"];
450			}
451	
452			if (result.from_mitsuba) {
453				result.scale = 0.66f;
454				result.offset = {0.25f * result.scale, 0.25f * result.scale, 0.25f * result.scale};
455			}
456	
457			if (json.contains("render_aabb")) {
458				result.render_aabb.min={float(json["render_aabb"][0][0]),float(json["render_aabb"][0][1]),float(json["render_aabb"][0][2])};
459				result.render_aabb.max={float(json["render_aabb"][1][0]),float(json["render_aabb"][1][1]),float(json["render_aabb"][1][2])};
460			}
461	
462			if (json.contains("sharpen")) {
463				sharpen_amount = json["sharpen"];
464			}
465	
466			if (json.contains("white_transparent")) {
467				info.white_transparent = bool(json["white_transparent"]);
468			}
469	
470			if (json.contains("black_transparent")) {
471				info.black_transparent = bool(json["black_transparent"]);
472			}
473	
474			if (json.contains("scale")) {
475				result.scale = json["scale"];
476			}
477	
478			if (json.contains("importance_sampling")) {
479				result.wants_importance_sampling = json["importance_sampling"];
480			}
481	
482			if (json.contains("n_extra_learnable_dims")) {
483				result.n_extra_learnable_dims = json["n_extra_learnable_dims"];
484			}
485	
486			Lens lens = {};
487			vec2 principal_point = vec2(0.5f);
488			vec4 rolling_shutter = vec4(0.0f);
489	
490			if (json.contains("integer_depth_scale")) {
491				info.depth_scale = json["integer_depth_scale"];
492			}
493	
494			// Lens parameters
495			read_lens(json, lens, principal_point, rolling_shutter);
496	
497			if (json.contains("aabb_scale")) {
498				result.aabb_scale = json["aabb_scale"];
499			}
500	
501			if (json.contains("offset")) {
502				result.offset =
503					json["offset"].is_array() ?
504					vec3{float(json["offset"][0]), float(json["offset"][1]), float(json["offset"][2])} :
505					vec3{float(json["offset"]), float(json["offset"]), float(json["offset"])};
506			}
507	
508			if (json.contains("aabb")) {
509				// map the given aabb of the form [[minx,miny,minz],[maxx,maxy,maxz]] via an isotropic scale and translate to fit in the (0,0,0)-(1,1,1) cube, with the given center at 0.5,0.5,0.5
510				const auto& aabb=json["aabb"];
511				float length = std::max(0.000001f,std::max(std::max(std::abs(float(aabb[1][0])-float(aabb[0][0])),std::abs(float(aabb[1][1])-float(aabb[0][1]))),std::abs(float(aabb[1][2])-float(aabb[0][2]))));
512				result.scale = 1.f/length;
513				result.offset = { ((float(aabb[1][0])+float(aabb[0][0]))*0.5f)*-result.scale + 0.5f , ((float(aabb[1][1])+float(aabb[0][1]))*0.5f)*-result.scale + 0.5f,((float(aabb[1][2])+float(aabb[0][2]))*0.5f)*-result.scale + 0.5f};
514			}
515	
516			if (json.contains("frames") && json["frames"].is_array()) {
517				for (int j = 0; j < json["frames"].size(); ++j) {
518					auto& frame = json["frames"][j];
519					nlohmann::json& jsonmatrix_start = frame.contains("transform_matrix_start") ? frame["transform_matrix_start"] : frame["transform_matrix"];
520					nlohmann::json& jsonmatrix_end = frame.contains("transform_matrix_end") ? frame["transform_matrix_end"] : jsonmatrix_start;
521					const vec3 p = vec3{float(jsonmatrix_start[0][3]), float(jsonmatrix_start[1][3]), float(jsonmatrix_start[2][3])} * result.scale + result.offset;
522					const vec3 q = vec3{float(jsonmatrix_end[0][3]), float(jsonmatrix_end[1][3]), float(jsonmatrix_end[2][3])} * result.scale + result.offset;
523					cam_aabb.enlarge(p);
524					cam_aabb.enlarge(q);
525				}
526			}
527	
528			if (json.contains("up")) {
529				// axes are permuted as for the xforms below
530				result.up[0] = float(json["up"][1]);
531				result.up[1] = float(json["up"][2]);
532				result.up[2] = float(json["up"][0]);
533			}
534	
535			if (json.contains("envmap") && product(result.envmap_resolution) > 0) {
536				fs::path envmap_path = resolve_path(base_path, json["envmap"]);
537				if (!envmap_path.exists()) {
538					throw std::runtime_error{fmt::format("Environment map {} does not exist.", envmap_path.str())};
539				}
540	
541				if (equals_case_insensitive(envmap_path.extension(), "exr")) {
542					result.envmap_data = load_exr_gpu(envmap_path, &result.envmap_resolution.x, &result.envmap_resolution.y);
543					result.is_hdr = true;
544				} else {
545					result.envmap_data = load_stbi_gpu(envmap_path, &result.envmap_resolution.x, &result.envmap_resolution.y);
546				}
547			}
548	
549	
550			if (json.contains("frames") && json["frames"].is_array()) pool.parallel_for_async<size_t>(0, json["frames"].size(), [&progress, &n_loaded, &result, &images, &json, &resolve_path, &supported_image_formats, base_path, image_idx, info, rolling_shutter, principal_point, lens, part_after_underscore, fix_premult, enable_depth_loading, enable_ray_loading](size_t i) {
551				size_t i_img = i + image_idx;
552				auto& frame = json["frames"][i];
553				LoadedImageInfo& dst = images[i_img];
554				dst = info; // copy defaults
555	
556				std::string json_provided_path = frame["file_path"];
557				if (json_provided_path == "") {
558					char buf[256];
559					snprintf(buf, 256, "%s_%03d/rgba.png", part_after_underscore.c_str(), (int)i);
560					json_provided_path = buf;
561				}
562	
563				fs::path path = resolve_path(base_path, json_provided_path);
564				if (!path.exists()) {
565					throw std::runtime_error{fmt::format("Could not find image file '{}'.", path.str())};
566				}
567	
568				int comp = 0;
569				if (equals_case_insensitive(path.extension(), "exr")) {
570					dst.pixels = load_exr_to_gpu(&dst.res.x, &dst.res.y, path.str().c_str(), fix_premult);
571					dst.image_type = EImageDataType::Half;
572					dst.image_data_on_gpu = true;
573					result.is_hdr = true;
574				} else {
575					dst.image_data_on_gpu = false;
576					uint8_t* img = load_stbi(path, &dst.res.x, &dst.res.y, &comp, 4);
577					if (!img) {
578						throw std::runtime_error{"Could not open image file: "s + std::string{stbi_failure_reason()}};
579					}
580	
581					fs::path alphapath = resolve_path(base_path, fmt::format("{}.alpha.{}", frame["file_path"], path.extension()));
582					if (alphapath.exists()) {
583						int wa = 0, ha = 0;
584						uint8_t* alpha_img = load_stbi(alphapath, &wa, &ha, &comp, 4);
585						if (!alpha_img) {
586							throw std::runtime_error{"Could not load alpha image "s + alphapath.str()};
587						}
588	
589						ScopeGuard mem_guard{[&]() { stbi_image_free(alpha_img); }};
590						if (wa != dst.res.x || ha != dst.res.y) {
591							throw std::runtime_error{fmt::format("Alpha image {} has wrong resolution.", alphapath.str())};
592						}
593	
594						tlog::success() << "Alpha loaded from " << alphapath;
595						for (int i = 0; i < product(dst.res); ++i) {
596							img[i*4+3] = (uint8_t)(255.0f*srgb_to_linear(alpha_img[i*4]*(1.f/255.f))); // copy red channel of alpha to alpha.png to our alpha channel
597						}
598					}
599	
600					fs::path maskpath = path.parent_path() / fmt::format("dynamic_mask_{}.png", path.basename());
601					if (maskpath.exists()) {
602						int wa = 0, ha = 0;
603						uint8_t* mask_img = load_stbi(maskpath, &wa, &ha, &comp, 4);
604						if (!mask_img) {
605							throw std::runtime_error{fmt::format("Dynamic mask {} could not be loaded.", maskpath.str())};
606						}
607	
608						ScopeGuard mem_guard{[&]() { stbi_image_free(mask_img); }};
609						if (wa != dst.res.x || ha != dst.res.y) {
610							throw std::runtime_error{fmt::format("Dynamic mask {} has wrong resolution.", maskpath.str())};
611						}
612	
613						dst.mask_color = 0x00FF00FF; // HOT PINK
614						for (int i = 0; i < product(dst.res); ++i) {
615							if (mask_img[i*4] != 0 || mask_img[i*4+1] != 0 || mask_img[i*4+2] != 0) {
616								*(uint32_t*)&img[i*4] = dst.mask_color;
617							}
618						}
619					}
620	
621					dst.pixels = img;
622					dst.image_type = EImageDataType::Byte;
623				}
624	
625				if (!dst.pixels) {
626					throw std::runtime_error{fmt::format("Could not load image file '{}'.", path.str())};
627				}
628	
629				if (enable_depth_loading && info.depth_scale > 0.f && frame.contains("depth_path")) {
630					fs::path depthpath = resolve_path(base_path, frame["depth_path"]);
631					if (depthpath.exists()) {
632						int wa = 0, ha = 0;
633						dst.depth_pixels = load_stbi_16(depthpath, &wa, &ha, &comp, 1);
634						if (!dst.depth_pixels) {
635							throw std::runtime_error{fmt::format("Could not load depth image '{}'.", depthpath.str())};
636						}
637	
638						if (wa != dst.res.x || ha != dst.res.y) {
639							throw std::runtime_error{fmt::format("Depth image {} has wrong resolution.", depthpath.str())};
640						}
641					}
642				}
643	
644				fs::path rayspath = path.parent_path() / fmt::format("rays_{}.dat", path.basename());
645				if (enable_ray_loading && rayspath.exists()) {
646					uint32_t n_pixels = product(dst.res);
647					dst.rays = (Ray*)malloc(n_pixels * sizeof(Ray));
648	
649					std::ifstream rays_file{native_string(rayspath), std::ios::binary};
650					rays_file.read((char*)dst.rays, n_pixels * sizeof(Ray));
651	
652					std::streampos fsize = 0;
653					fsize = rays_file.tellg();
654					rays_file.seekg(0, std::ios::end);
655					fsize = rays_file.tellg() - fsize;
656	
657					if (fsize > 0) {
658						tlog::warning() << fsize << " bytes remaining in rays file " << rayspath;
659					}
660	
661					for (uint32_t px = 0; px < n_pixels; ++px) {
662						result.nerf_ray_to_ngp(dst.rays[px]);
663					}
664	
665					result.has_rays = true;
666				}
667	
668				nlohmann::json& jsonmatrix_start = frame.contains("transform_matrix_start") ? frame["transform_matrix_start"] : frame["transform_matrix"];
669				nlohmann::json& jsonmatrix_end = frame.contains("transform_matrix_end") ? frame["transform_matrix_end"] : jsonmatrix_start;
670	
671				if (frame.contains("driver_parameters")) {
672					vec3 light_dir{
673						frame["driver_parameters"].value("LightX", 0.f),
674						frame["driver_parameters"].value("LightY", 0.f),
675						frame["driver_parameters"].value("LightZ", 0.f)
676					};
677					result.metadata[i_img].light_dir = result.nerf_direction_to_ngp(normalize(light_dir));
678					result.has_light_dirs = true;
679					result.n_extra_learnable_dims = 0;
680				}
681	
682				bool got_fl = read_focal_length(json, result.metadata[i_img].focal_length, dst.res);
683				got_fl |= read_focal_length(frame, result.metadata[i_img].focal_length, dst.res);
684				if (!got_fl) {
685					throw std::runtime_error{"Couldn't read fov."};
686				}
687	
688				for (int m = 0; m < 3; ++m) {
689					for (int n = 0; n < 4; ++n) {
690						result.xforms[i_img].start[n][m] = float(jsonmatrix_start[m][n]);
691						result.xforms[i_img].end[n][m] = float(jsonmatrix_end[m][n]);
692					}
693				}
694	
695				// set these from the base settings
696				result.metadata[i_img].rolling_shutter = rolling_shutter;
697				result.metadata[i_img].principal_point = principal_point;
698				result.metadata[i_img].lens = lens;
699				// see if there is a per-frame override
700				read_lens(frame, result.metadata[i_img].lens, result.metadata[i_img].principal_point, result.metadata[i_img].rolling_shutter);
701	
702				result.xforms[i_img].start = result.nerf_matrix_to_ngp(result.xforms[i_img].start);
703				result.xforms[i_img].end = result.nerf_matrix_to_ngp(result.xforms[i_img].end);
704	
705				progress.update(++n_loaded);
706			}, futures);
707	
708			if (json.contains("frames")) {
709				image_idx += json["frames"].size();
710			}
711	
712		}
713	
714		wait_all(futures);
715	
716		tlog::success() << "Loaded " << images.size() << " images after " << tlog::durationToString(progress.duration());
717		tlog::info() << "  cam_aabb=" << cam_aabb;
718	
719		if (result.has_rays) {
720			tlog::success() << "Loaded per-pixel rays.";
721		}
722		if (!images.empty() && images[0].mask_color) {
723			tlog::success() << "Loaded dynamic masks.";
724		}
725	
726		result.sharpness_resolution = { 128, 72 };
727		result.sharpness_data.enlarge( result.sharpness_resolution.x * result.sharpness_resolution.y *  result.n_images );
728	
729		// copy / convert images to the GPU
730		for (uint32_t i = 0; i < result.n_images; ++i) {
731			const LoadedImageInfo& m = images[i];
732			result.set_training_image(i, m.res, m.pixels, m.depth_pixels, m.depth_scale * result.scale, m.image_data_on_gpu, m.image_type, EDepthDataType::UShort, sharpen_amount, m.white_transparent, m.black_transparent, m.mask_color, m.rays);
733			CUDA_CHECK_THROW(cudaDeviceSynchronize());
734		}
735		CUDA_CHECK_THROW(cudaDeviceSynchronize());
736		// free memory
737		for (uint32_t i = 0; i < result.n_images; ++i) {
738			if (images[i].image_data_on_gpu) {
739				CUDA_CHECK_THROW(cudaFree(images[i].pixels));
740			} else {
741				free(images[i].pixels);
742			}
743			free(images[i].rays);
744			free(images[i].depth_pixels);
745		}
746		return result;
747	}
748	
749	void NerfDataset::set_training_image(int frame_idx, const ivec2& image_resolution, const void* pixels, const void* depth_pixels, float depth_scale, bool image_data_on_gpu, EImageDataType image_type, EDepthDataType depth_type, float sharpen_amount, bool white_transparent, bool black_transparent, uint32_t mask_color, const Ray *rays) {
750		if (frame_idx < 0 || frame_idx >= n_images) {
751			throw std::runtime_error{"NerfDataset::set_training_image: invalid frame index"};
752		}
753	
754		size_t n_pixels = product(image_resolution);
755		size_t img_size = n_pixels * 4; // 4 channels
756		size_t image_type_stride = image_type_size(image_type);
757		// copy to gpu if we need to do a conversion
758		GPUMemory<uint8_t> images_data_gpu_tmp;
759		GPUMemory<uint8_t> depth_tmp;
760		if (!image_data_on_gpu && image_type == EImageDataType::Byte) {
761			images_data_gpu_tmp.resize(img_size * image_type_stride);
762			images_data_gpu_tmp.copy_from_host((uint8_t*)pixels);
763			pixels = images_data_gpu_tmp.data();
764	
765			if (depth_pixels) {
766				depth_tmp.resize(n_pixels * depth_type_size(depth_type));
767				depth_tmp.copy_from_host((uint8_t*)depth_pixels);
768				depth_pixels = depth_tmp.data();
769			}
770	
771			image_data_on_gpu = true;
772		}
773	
774		// copy or convert the pixels
775		pixelmemory[frame_idx].resize(img_size * image_type_size(image_type));
776		void* dst = pixelmemory[frame_idx].data();
777	
778		switch (image_type) {
779			default: throw std::runtime_error{"unknown image type in set_training_image"};
780			case EImageDataType::Byte: linear_kernel(convert_rgba32, 0, nullptr, n_pixels, (uint8_t*)pixels, (uint8_t*)dst, white_transparent, black_transparent, mask_color); break;
781			case EImageDataType::Half: // fallthrough is intended
782			case EImageDataType::Float: CUDA_CHECK_THROW(cudaMemcpy(dst, pixels, img_size * image_type_size(image_type), image_data_on_gpu ? cudaMemcpyDeviceToDevice : cudaMemcpyHostToDevice)); break;
783		}
784	
785		// copy over depths if provided
786		if (depth_scale >= 0.f) {
787			depthmemory[frame_idx].resize(img_size);
788			float* depth_dst = depthmemory[frame_idx].data();
789	
790			if (depth_pixels && !image_data_on_gpu) {
791				depth_tmp.resize(n_pixels * depth_type_size(depth_type));
792				depth_tmp.copy_from_host((uint8_t*)depth_pixels);
793				depth_pixels = depth_tmp.data();
794			}
795	
796			switch (depth_type) {
797				default: throw std::runtime_error{"unknown depth type in set_training_image"};
798				case EDepthDataType::UShort: linear_kernel(copy_depth<uint16_t>, 0, nullptr, n_pixels, depth_dst, (const uint16_t*)depth_pixels, depth_scale); break;
799				case EDepthDataType::Float: linear_kernel(copy_depth<float>, 0, nullptr, n_pixels, depth_dst, (const float*)depth_pixels, depth_scale); break;
800			}
801		} else {
802			depthmemory[frame_idx].free_memory();
803		}
804	
805		// apply requested sharpening
806		if (sharpen_amount > 0.f) {
807			if (image_type == EImageDataType::Byte) {
808				GPUMemory<uint8_t> images_data_half(img_size * sizeof(__half));
809				linear_kernel(from_rgba32<__half>, 0, nullptr, n_pixels, (uint8_t*)pixels, (__half*)images_data_half.data(), white_transparent, black_transparent, mask_color);
810				pixelmemory[frame_idx] = std::move(images_data_half);
811				dst = pixelmemory[frame_idx].data();
812				image_type = EImageDataType::Half;
813			}
814	
815			assert(image_type == EImageDataType::Half || image_type == EImageDataType::Float);
816	
817			GPUMemory<uint8_t> images_data_sharpened(img_size * image_type_size(image_type));
818	
819			float center_w = 4.f + 1.f / sharpen_amount; // center_w ranges from 5 (strong sharpening) to infinite (no sharpening)
820			if (image_type == EImageDataType::Half) {
821				linear_kernel(sharpen<__half>, 0, nullptr, n_pixels, image_resolution.x, (__half*)dst, (__half*)images_data_sharpened.data(), center_w, 1.f / (center_w - 4.f));
822			} else {
823				linear_kernel(sharpen<float>, 0, nullptr, n_pixels, image_resolution.x, (float*)dst, (float*)images_data_sharpened.data(), center_w, 1.f / (center_w - 4.f));
824			}
825	
826			pixelmemory[frame_idx] = std::move(images_data_sharpened);
827			dst = pixelmemory[frame_idx].data();
828		}
829	
830		if (sharpness_data.size() > 0) {
831			// compute overall sharpness
832			const dim3 threads = { 16, 8, 1 };
833			const dim3 blocks = { div_round_up((uint32_t)sharpness_resolution.x, threads.x), div_round_up((uint32_t)sharpness_resolution.y, threads.y), 1 };
834			sharpness_data.enlarge(sharpness_resolution.x * sharpness_resolution.y);
835			compute_sharpness<<<blocks, threads, 0, nullptr>>>(sharpness_resolution, image_resolution, 1, dst, image_type, sharpness_data.data() + sharpness_resolution.x * sharpness_resolution.y * (size_t)frame_idx);
836		}
837	
838		metadata[frame_idx].pixels = pixelmemory[frame_idx].data();
839		metadata[frame_idx].depth = depthmemory[frame_idx].data();
840		metadata[frame_idx].resolution = image_resolution;
841		metadata[frame_idx].image_data_type = image_type;
842		if (rays) {
843			raymemory[frame_idx].resize(n_pixels);
844			CUDA_CHECK_THROW(cudaMemcpy(raymemory[frame_idx].data(), rays, n_pixels * sizeof(Ray), cudaMemcpyHostToDevice));
845		} else {
846			raymemory[frame_idx].free_memory();
847		}
848		metadata[frame_idx].rays = raymemory[frame_idx].data();
849		update_metadata(frame_idx, frame_idx + 1);
850	}
851	
852	void NerfDataset::update_metadata(int first, int last) {
853		if (last < 0) {
854			last = n_images;
855		}
856	
857		if (last > n_images) {
858			last = n_images;
859		}
860	
861		int n = last - first;
862		if (n <= 0) {
863			return;
864		}
865	
866		metadata_gpu.enlarge(last);
867		CUDA_CHECK_THROW(cudaMemcpy(metadata_gpu.data() + first, metadata.data() + first, n * sizeof(TrainingImageMetadata), cudaMemcpyHostToDevice));
868	}
869	
870	}
